  "inlineSchema": "generator client {\n  provider = \"prisma-client-js\"\n}\n\ndatasource db {\n  provider  = \"postgresql\"\n  url       = env(\"DATABASE_URL\")\n  directUrl = env(\"DIRECT_URL\")\n}\n\n// ==========================================\n// ENUMS\n// ==========================================\n\n/// Defines the role of a user within the LEO ecosystem.\nenum Role {\n  CREATOR\n  CONSUMER\n  OPERATOR\n  ADMIN\n  RESEARCHER\n  DEVELOPER\n}\n\n/// Tracks the lifecycle of a cognitive workflow execution.\nenum SessionStatus {\n  PENDING\n  RUNNING\n  COMPLETED\n  FAILED\n  DISPUTED\n}\n\n/// Tracks the lifecycle of an individual AI agent node execution.\nenum NodeStatus {\n  QUEUED\n  RUNNING\n  COMPLETED\n  FAILED\n}\n\n/// Represents the state of a USDC nanopayment on Arc L1.\nenum PaymentStatus {\n  PENDING\n  LOCKED\n  RELEASED\n  REFUNDED\n  DISPUTED\n}\n\n/// Defines types of auth tokens\nenum TokenType {\n  REFRESH\n  RESET_PASSWORD\n}\n\n// ==========================================\n// MODELS\n// ==========================================\n\n/// The core identity of a participant on the platform.\nmodel User {\n  id          String   @id @default(uuid())\n  email       String   @unique\n  password    String\n  did         String?  @unique // Decentralized Identifier tied to on-chain identity\n  displayName String?\n  role        Role     @default(CONSUMER)\n  createdAt   DateTime @default(now())\n  updatedAt   DateTime @updatedAt\n\n  wallets          Wallet[]\n  apiKeys          APIKey[]\n  researchSessions ResearchSession[]\n  tokens           Token[]\n\n  @@index([email])\n  @@index([did])\n}\n\n/// A blockchain wallet belonging to a User, used for Arc L1 payments and signatures.\nmodel Wallet {\n  id        String   @id @default(uuid())\n  userId    String\n  address   String   @unique\n  chain     String   @default(\"arc\")\n  createdAt DateTime @default(now())\n\n  user          User          @relation(fields: [userId], references: [id], onDelete: Cascade)\n  paymentsPayer Payment[]     @relation(\"PayerWallet\")\n  paymentsPayee Payment[]     @relation(\"PayeeWallet\")\n  transactions  Transaction[]\n\n  @@index([userId])\n  @@index([address])\n}\n\n/// Stores authentication tokens\nmodel Token {\n  id          String    @id @default(uuid())\n  token       String    @unique\n  userId      String\n  type        TokenType\n  expires     DateTime\n  blacklisted Boolean   @default(false)\n  createdAt   DateTime  @default(now())\n\n  user User @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  @@index([userId])\n  @@index([token])\n}\n\n/// API Keys for programmatic access by developers or agent operators.\nmodel APIKey {\n  id        String    @id @default(uuid())\n  userId    String\n  keyHash   String    @unique // Hashed key for security; raw key never stored\n  name      String\n  expiresAt DateTime?\n  createdAt DateTime  @default(now())\n\n  user User @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  @@index([userId])\n}\n\n/// Represents an active or completed execution of a cognitive workflow.\nmodel ResearchSession {\n  id         String        @id @default(uuid())\n  userId     String // The Consumer who initiated the workflow\n  workflowId String // Hash/ID of the workflow blueprint on IPFS\n  status     SessionStatus @default(PENDING)\n  totalCost  Decimal       @default(0.0) @db.Decimal(18, 6) // Supports USDC nanopayments precision\n  createdAt  DateTime      @default(now())\n  updatedAt  DateTime      @updatedAt\n\n  user             User              @relation(fields: [userId], references: [id], onDelete: Cascade)\n  workflowNodes    WorkflowNode[]\n  payments         Payment[]\n  verificationLogs VerificationLog[]\n  merkleRoot       MerkleRoot?\n\n  @@index([userId])\n  @@index([status])\n}\n\n/// An individual step (e.g., an LLM call or tool execution) within a ResearchSession.\nmodel WorkflowNode {\n  id        String     @id @default(uuid())\n  sessionId String\n  stepIndex Int\n  agentDid  String // The DID of the specific AI Agent handling this node\n  status    NodeStatus @default(QUEUED)\n  startTime DateTime?\n  endTime   DateTime?\n  createdAt DateTime   @default(now())\n\n  session           ResearchSession    @relation(fields: [sessionId], references: [id], onDelete: Cascade)\n  hashes            Hash[]\n  blockchainReceipt BlockchainReceipt?\n\n  @@unique([sessionId, stepIndex])\n  @@index([sessionId])\n}\n\n/// Cryptographic hashes of inputs, outputs, or state for a WorkflowNode.\n/// Storing only the hash ensures data privacy while maintaining tamper-evidence.\nmodel Hash {\n  id        String   @id @default(uuid())\n  nodeId    String\n  type      String // e.g., 'INPUT', 'OUTPUT', 'STATE'\n  hashValue String\n  createdAt DateTime @default(now())\n\n  node WorkflowNode @relation(fields: [nodeId], references: [id], onDelete: Cascade)\n\n  @@index([nodeId])\n}\n\n/// The aggregated cryptographic root of all Hashes in a ResearchSession.\nmodel MerkleRoot {\n  id        String   @id @default(uuid())\n  sessionId String   @unique\n  rootHash  String   @unique\n  createdAt DateTime @default(now())\n\n  session           ResearchSession    @relation(fields: [sessionId], references: [id], onDelete: Cascade)\n  blockchainReceipt BlockchainReceipt?\n\n  @@index([rootHash])\n}\n\n/// An on-chain proof (receipt) anchored to Arc L1. \n/// Can be tied to a single step (WorkflowNode) or the entire workflow (MerkleRoot).\nmodel BlockchainReceipt {\n  id           String   @id @default(uuid())\n  nodeId       String?  @unique\n  merkleRootId String?  @unique\n  signature    String // The operator's cryptographic signature confirming execution\n  createdAt    DateTime @default(now())\n\n  node        WorkflowNode? @relation(fields: [nodeId], references: [id], onDelete: Cascade)\n  merkleRoot  MerkleRoot?   @relation(fields: [merkleRootId], references: [id], onDelete: Cascade)\n  transaction Transaction?\n\n  @@index([nodeId])\n  @@index([merkleRootId])\n}\n\n/// Tracks the lifecycle of USDC nanopayments in the Escrow Vault.\nmodel Payment {\n  id            String        @id @default(uuid())\n  sessionId     String\n  payerWalletId String\n  payeeWalletId String\n  amountUsdc    Decimal       @db.Decimal(18, 6)\n  status        PaymentStatus @default(PENDING)\n  createdAt     DateTime      @default(now())\n  updatedAt     DateTime      @updatedAt\n\n  session     ResearchSession @relation(fields: [sessionId], references: [id], onDelete: Cascade)\n  payer       Wallet          @relation(\"PayerWallet\", fields: [payerWalletId], references: [id])\n  payee       Wallet          @relation(\"PayeeWallet\", fields: [payeeWalletId], references: [id])\n  transaction Transaction?\n\n  @@index([sessionId])\n  @@index([payerWalletId])\n  @@index([payeeWalletId])\n  @@index([status])\n}\n\n/// Represents a raw blockchain transaction on the Arc network.\nmodel Transaction {\n  id        String   @id @default(uuid())\n  txHash    String   @unique\n  walletId  String?\n  paymentId String?  @unique\n  receiptId String?  @unique\n  chain     String   @default(\"arc\")\n  status    String   @default(\"CONFIRMED\")\n  createdAt DateTime @default(now())\n\n  wallet  Wallet?            @relation(fields: [walletId], references: [id])\n  payment Payment?           @relation(fields: [paymentId], references: [id], onDelete: Cascade)\n  receipt BlockchainReceipt? @relation(fields: [receiptId], references: [id], onDelete: Cascade)\n\n  @@index([txHash])\n  @@index([walletId])\n}\n\n/// An audit trail logging every time a cryptographic proof is verified by a third party.\nmodel VerificationLog {\n  id         String   @id @default(uuid())\n  sessionId  String\n  verifierIp String?\n  isValid    Boolean\n  verifiedAt DateTime @default(now())\n\n  session ResearchSession @relation(fields: [sessionId], references: [id], onDelete: Cascade)\n\n  @@index([sessionId])\n}\n",
